var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_TYPE_A","text":{"KOREA":"막아야 해……. 관리국을 막는 거야…….","JPN":"阻止するんだ……管理局を阻止する……","ENG":"Must stop... Must stop the Administration...","TWN":"必須阻止他們……阻止管理局……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_TYPE_A","face":"UNIT_SERIOUS2"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_TYPE_A","text":{"KOREA":"막아. 목숨을 다해서라도…….","JPN":"防げ。命を捧げてでも……","ENG":"Stop them. With our lives...","TWN":"阻止。哪怕獻上生命……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GSWORD_ADMIN_TYPE_A","face":"UNIT_SERIOUS2"}}}},{"id":"L11_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"젠장! 실험체들이 끝도 없이 밀려오잖아!","JPN":"くそ！　キリがないぞ！","ENG":"Dammit! These test subjects keep coming in!","TWN":"該死！實驗體的數量也太多了！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"망할 그림자 자식들! 대체 얼마나 많이 만들어 낸 거야!","JPN":"シャドウどもめ、どれだけ量産しやがったんだ！","ENG":"Those damn Shadows! How many of these did they make?!","TWN":"該死的暗影！她們到底製造了多少這種東西！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"부상을 당해도 계속 밀고 들어오고 있어.","JPN":"負傷しても構わずに押し寄せてくる。","ENG":"They keep pushing even if they're injured!","TWN":"這幫傢伙即便受了傷也要繼續衝過來！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"다들 동정심 갖지 마! 우린 지금 싸우러 여기 온 거다!","JPN":"同情するな！　我々は今ここに戦うために来ているんだ！","ENG":"Don't be sympathetic! We're here to fight!","TWN":"別可憐它們！我們是來戰鬥的！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"엘리시움 필하모닉의 실험체들인가…….","JPN":"エリシウムフィルハーモニーの実験体か……","ENG":"Are those Elysium Philharmonic's test subjects...?","TWN":"這些都是來自樂團的實驗體嗎……？"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOCUS_BLUR"},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"단지 멘탈프린팅을 위해 복제되었다는 이유만으로 이들과 싸워야 한다니…….","JPN":"メンタル・プリンティングのためだけに複製された彼らと戦わねばならないとは……","ENG":"So we have to fight them just because they were cloned for Mental Printing...","TWN":"只因為要實驗智力複印，我們就必須和它們戰鬥……"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"숫자만 많을 뿐 하나같이 그저 평범한 인간이지 않나…….","JPN":"数が多いだけで、中身は普通の人間だというのに……","ENG":"Except for their numbers, aren't they still just ordinary humans...?","TWN":"雖然數量很多，但不都是普通人類嗎……？"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"빌어먹을! 사격 개시!","JPN":"くそ！　射撃開始！","ENG":"Dammit! Shoot to kill!","TWN":"該死！快開火！"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"멘탈프린팅에 의해 조종당하는 실험체들이다!","JPN":"メンタル・プリンティングに操られている実験体だ！","ENG":"Those are test subjects controlled by Mental Printing!","TWN":"這些是被控制了的實驗體！"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"사살하지 않으면 막을 수 없어!","JPN":"射殺以外止める方法はない！","ENG":"They won't stop until they're dead!","TWN":"除非殺死它們，否則無法阻止敵人突襲！"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"피……!","JPN":"血……！","ENG":"Blood...!","TWN":"血……！"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"전장이 참혹하지 않을 리 없다만…… 오늘은 더 끔찍하군.","JPN":"戦場とは本来残酷なものだが……今日は一段と酷いな。","ENG":"I know battlefields are cruel... but it seems more terrible today.","TWN":"戰場都是殘酷的……今天更加可怕。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"류드밀라 전대장님!","JPN":"リュドミラ戦隊長！","ENG":"Commander Lyudmila!","TWN":"盧德米拉戰隊長！"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L39_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"에스타크 자주 곡사포 72문 일제 사격 준비가 완료되었습니다.","JPN":"エスターク自主曲射砲72門、一斉射撃準備完了です。","ENG":"A salvo of seventy-two Estaque self-propelled howitzers is ready for volley fire.","TWN":"72門艾斯塔克自主高射炮已做好射擊準備。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이어서 약 4분 11초 뒤에 다음 사격 준비가 완료됩니다.","JPN":"約4分11秒後、次の射撃準備が完了します。","ENG":"The next rounds will be ready in approximately four minutes and eleven seconds.","TWN":"大約4分11秒後，下一次射擊準備就緒。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……알겠다.","JPN":"……わかった。","ENG":"...Good.","TWN":"……我知道了。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그래. 여기는 전쟁터. 어쩔 수 없는 일이겠지.","JPN":"そうだ、ここは戦場。仕方ないことだろう。","ENG":"Okay. This is a battlefield. It is inevitable.","TWN":"好。這裡是戰場。這是沒有辦法的事。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"しかし……","ENG":"But...","TWN":"但……"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"더 빨리……!","JPN":"もっと早く……！","ENG":"Faster...!","TWN":"再快點……！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE"},{"id":"L2_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"1초라도 더 빨리……!","JPN":"1秒でも早く……！","ENG":"Even a second faster...!","TWN":"再快1秒……！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L4_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"마, 말도…… 안 됩니다요……!","JPN":"ば、バカな……あり得ないでやんす！","ENG":"Th-that's... impossible...!","TWN":"不……不可能……！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L5_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"비스트 클로를 착용한 채로 그렇게 빠르게 움직이다니!","JPN":"ビーストクローを装備した状態で、あんな動きができるなんて！","ENG":"How are you moving that fast with Beast Claw equipped?","TWN":"你穿著魔獸爪怎麼可能移動得這麼快！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"심지어 점점 가속하고 있습니다요! 원래라면 이런 출력이 나올 리가 없는데……!","JPN":"しかもどんどん加速してるでやんす！　こんな出力がでるはずないのに……！","ENG":"It's not just that, you're accelerating! Normally, this kind of output is impossible...!","TWN":"你甚至還在加速！理論上，不可能會有這樣的輸出的……！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"하아, 하아, 하아……!!","JPN":"はあ、はあ、はあ……！！","ENG":"*Huff* *Huff* *Huff*","TWN":"哈啊，哈啊，哈啊……！！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_05"},{"id":"L10_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"귀 옆에서 그만 쫑알쫑알거려, 꼬맹아.","JPN":"ぶつぶつうるさいぞ、チビ。","ENG":"Will you stop yapping in my ear, kid?","TWN":"別碎碎念了，小鬼。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"내가 선택한 녀석이야. 이 정도는 날뛰게 해줘야 만족하지 않겠어?","JPN":"アタシが選んだヤツだ。これぐらい暴れさせないと、こいつも満足できないだろう？","ENG":"I picked it. Don't you think it has to run this wild in order to be satisfied?","TWN":"這傢伙可是我選的，這種程度的速度怎麼可能滿足？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"앨리스 브레이드우드.","JPN":"アリス・ブレイドウッド。","ENG":"Alice Braidwood.","TWN":"艾莉絲·布雷德伍德。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"잘해주었다. 기갑 병기의 배치 완료 보고를 들었다.","JPN":"よくやってくれた。機甲兵器の配置完了報告が届いている。","ENG":"Good work. I've received word that the armored vehicles are successfully deployed.","TWN":"做得好。我已收到消息，裝甲武器已部署完畢。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지금부터 작전 구역에 플라즈마 입자포를 일제 사격하여 최전방까지 길을 열겠다.","JPN":"これより作戦区域にプラズマ粒子砲を一斉射撃し、最前線まで道を開く。","ENG":"Now, we'll fire a volley of plasma particle cannons toward the operation zone's area, creating a straight path to the forefront.","TWN":"從現在開始，我們將向作戰區域投射離子粒子炮，為前線掃清道路。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"마침내……!","JPN":"ついに……！","ENG":"Finally...!","TWN":"終於……！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그러니 가라!","JPN":"だから行け！","ENG":"Now, go!","TWN":"所以，上吧！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"가서 연합 전대와 합류하도록!","JPN":"行って、連合戦隊と合流せよ！","ENG":"Go help the coalition divisions!","TWN":"快去與聯合戰隊會合！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"알겠습니다!","JPN":"了解しました！","ENG":"Roger that!","TWN":"明白！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"메이즈 전대장님께서는 어떻게 하실 겁니까……!","JPN":"メイズ戦隊長は、どうされますか……！","ENG":"What will you be doing, Maze Commander?","TWN":"梅茲戰隊長你要怎麼做……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"우린 이곳에 있는 실험체들을 외면할 수 없다.","JPN":"ここにいる実験体どもを放っておく訳にはいかない。","ENG":"We can't ignore the test subjects here.","TWN":"我們不能放任這裡的實驗體不管。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그러니 일단 이곳에 남겠다.","JPN":"だから私はとりあえずここに残る。","ENG":"So for now, we'll stay here.","TWN":"所以，我暫時留在這裡。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그게 무슨 말씀입니까!","JPN":"そんな……！","ENG":"What do you mean?","TWN":"你說什麼！"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"착각하지 마라. 작전의 우선순위도 파악하지 못할 만큼 어리석지는 않아.","JPN":"勘違いするな。作戦の優先順位も把握できないほど愚かではない。","ENG":"Don't be mistaken. I am not foolish enough to mix up the operation priorities.","TWN":"別誤會了。我還沒有傻到分不清作戰的優先次序。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 우리 전대는 그 특성상, 나 이외의 전대 전원은 관리국의 병사. 복제 인간이다.","JPN":"しかし我々の戦隊は特性上、私以外のすべての隊員が管理局の兵士。つまり複製人間だ。","ENG":"However, due to the nature of my division, everyone other than me in this division is a soldier of the Administration. A clone.","TWN":"但由於我們戰隊的性質，除了我以外的其他隊員都是管理局的士兵、複製人。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"복제라고 그 생명이 무가치할 리 없어. 그건 어느 전대보다 우리가 가장 잘 알고 있다.","JPN":"複製だからと言ってそれぞれの命が無価値な訳がない。それは私たちが誰よりも理解している。","ENG":"Being a clone doesn't mean that their lives hold no value. We know that better than any division.","TWN":"不會因為是複製人生命就毫無價值，這一點，我們最清楚不過。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그러니 우리는 저들을 외면하지 않겠다.","JPN":"だから私たちは彼らを見捨てない。","ENG":"So, we will not neglect them.","TWN":"所以我們無法放任不管他們。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"저들 중에 단 한명이라도 적의 멘탈프린팅을 극복하고 투항 의사를 보낸다면…….","JPN":"彼らの中に一人でも、敵のメンタル・プリンティングを克服し、投降の意志を示す者が現れたら……","ENG":"If I see any signs of the enemy overcoming Mental Printing and willing to surrender...","TWN":"如果他們其中有人掙脫了控制，表現出投降的意願的話……"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"우리에겐 그 투항을 받아들여야만 하는 의무가 있다.","JPN":"私たちには、その意志を受け入れる義務がある。","ENG":"we have a duty to accept their surrender.","TWN":"我們有義務接受這種投降。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……알겠습니다.","JPN":"……承知しました。","ENG":"...Understood.","TWN":"……我知道了。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 마음, 저도 충분히 이해합니다. 전대장님.","JPN":"その気持ち、アタシにもよくわかります。戦隊長。","ENG":"I completely understand that feeling, Commander.","TWN":"我充分理解你的感受。戰隊長。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그러니까 가라. 자네에게는 반드시 구해야만 하는 동료가 있다고 하지 않았나?","JPN":"だから行け。君には必ず助けなければならない仲間がいるのだろう？","ENG":"So, go. Didn't you say you have comrades whom you must save?","TWN":"所以去吧，你不是還有必須要拯救的同伴嗎？"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지금의 자네라면, 충분히 늦지 않고 도착할 수 있을 거야.","JPN":"今の君なら、十分間に合う。","ENG":"Seeing you now, I'm confident you'll arrive on time.","TWN":"如果是現在的你，一定能夠及時趕到的。"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"감사합니다. 이곳까지 데려다 주셔서!","JPN":"ここまで連れてきてくださって、ありがとうございます！","ENG":"Thank you for taking me along!","TWN":"好的！謝謝，帶我來了這裡！"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"좋다! 다들 오래 기다려 주었다!","JPN":"よし！　皆、待たせてすまない！","ENG":"All right! You all have been patiently waiting!","TWN":"好！大家等很久了！"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지금부터 앨리스 전대원에게 길을 열어주겠다!","JPN":"これよりアリス戦隊員の進む道を開ける！","ENG":"Now, we will open the path for Alice!","TWN":"從現在開始，為艾莉絲戰員開闢道路！"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"에스타크 자주 곡사포 72문! 일제 사격 개시……!!","JPN":"エスターク自主曲射砲72門、一斉射撃開始……！！","ENG":"Volley fire the seventy-two Estaque self-propelled howitzers...!!","TWN":"72門艾斯塔克自主高射炮！開始發射……！！"},"stage":{"bg":"SKY_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};